segments.initScript:
(function() {
  var fakeGetUserMedia = async function() {
    var ctx = new AudioContext();
    var destination = ctx.createMediaStreamDestination();
    var osc = ctx.createOscillator();
    var gain = ctx.createGain();
    gain.gain.value = 0.05;
    osc.connect(gain);
    gain.connect(destination);
    osc.start();
    return destination.stream;
  };
  Object.defineProperty(navigator, 'mediaDevices', {
    value: { getUserMedia: fakeGetUserMedia },
    configurable: true
  });

  var NativeWebSocket = window.WebSocket;
  var armed = null;
  class TestWebSocket extends NativeWebSocket {
    constructor(url, protocols) {
      super(url, protocols);
      this.isStt = /\/api\/voice\/stream(\?|$)/.test(String(url));
    }
    send(data) {
      if (this.isStt && (data instanceof ArrayBuffer || ArrayBuffer.isView(data))) {
        if (armed !== null) {
          var key = armed;
          armed = null;
          var bytes = new TextEncoder().encode('EKOA-STT:' + key);
          super.send(bytes.buffer);
        }
        return;
      }
      super.send(data);
    }
  }
  Object.defineProperty(window, 'WebSocket', {
    value: TestWebSocket,
    configurable: true,
    writable: true
  });
  window.__voiceTestArmMarker = function(key) { armed = key; };

  window.__voiceE2eTestVadFactory = async function(hooks) {
    var speaking = false;
    window.__voiceTestVad = {
      fireSpeechStart: function() { speaking = true; hooks.onSpeechStart(); },
      fireSpeechEnd: function() { speaking = false; hooks.onSpeechEnd(); }
    };
    return {
      get speaking() { return speaking; },
      destroy: function() { window.__voiceTestVad = undefined; }
    };
  };
})();

