actions.script:
async () => {
  const start = Date.now();
  while (!window.__voiceTestVad) {
    if (Date.now() - start > 10000) throw new Error('vad hook not ready');
    await new Promise((r) => setTimeout(r, 100));
  }
  window.__voiceTestVad.fireSpeechStart();
}

